const now = new Date();
const today = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Seoul', year: 'numeric', month: '2-digit', day: '2-digit'
}).format(now);
const url = $env.SUPABASE_URL + '/rest/v1/articles?select=id,sector_id,sector_name,subject,summary,link,published_at,session&published_at=gte.' + today + 'T00:00:00%2B09:00&order=id.asc';
console.log('[NER] Query URL:', url);
return [{ json: { queryUrl: url, today } }];

// HTTP Request 출력: 배열이 $json에 직접 들어오거나 단일 아이템으로 옴
const input = $input.first().json;
let articles = [];

// HTTP Response가 배열이면 여러 아이템으로 들어옴
if (Array.isArray(input)) {
  articles = input;
} else if (input.id && input.subject) {
  // 단일 아이템으로 들어온 경우 — 모든 아이템 수집
  articles = $input.all().map(i => i.json);
} else {
  console.log('[NER] Unexpected response format:', Object.keys(input).join(','));
  return [];
}

if (articles.length === 0) {
  console.log('[NER] No articles found for today');
  return [];
}

console.log(`[NER] Found ${articles.length} articles`);

const BATCH_SIZE = 20;
const result = [];
for (let i = 0; i < articles.length; i += BATCH_SIZE) {
  const batch = articles.slice(i, i + BATCH_SIZE);
  const articleList = batch.map((a, j) =>
    `${j+1}. [${a.sector_name}] ${a.subject}${a.summary ? ' — ' + a.summary.slice(0, 100) : ''}`
  ).join('\n');

  const prompt = `아래 한국 금융 뉴스 기사 제목/요약에서 언급된 기업명을 추출하세요.

[기사 목록]
${articleList}

[규칙]
1. 한국 상장 기업(KOSPI/KOSDAQ)만 추출
2. 일반 명사(증시, 시장)나 기관명(한국은행, 금감원)은 제외
3. 약어도 정식 기업명으로 변환 (삼전→삼성전자, 현차→현대자동차)
4. 각 기업의 감성(positive/negative/neutral)과 맥락을 함께 추출

[출력 형식 - 반드시 JSON 배열만 출력]
[{"company":"삼성전자","article_index":1,"context":"HBM 양산 확대","sentiment":"positive"}]

JSON 배열만 출력하세요. 다른 텍스트는 포함하지 마세요.`;

  result.push({ json: { chatInput: prompt, articles: batch, batchIndex: Math.floor(i/BATCH_SIZE) } });
}

console.log(`[NER] Created ${result.length} batches`);
return result;

const ollamaResp = $json;
const batchData = $('Build NER Batches').item.json;
const articles = batchData.articles || [];

if (ollamaResp.error || !ollamaResp.response) {
  console.log('[NER] Ollama error:', ollamaResp.error || 'no response');
  return { json: { mentions: [] } };
}

let mentions = [];
try {
  let raw = ollamaResp.response || '';
  raw = raw.replace(/<thought>[\s\S]*?<\/think>/g, '').trim();
  const jsonMatch = raw.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    if (Array.isArray(parsed)) mentions = parsed;
  }
} catch (e) {
  console.log('[NER] JSON parse error:', e.message);
  return { json: { mentions: [] } };
}

// article_id 연결
const results = mentions.map(m => {
  const idx = (m.article_index || 1) - 1;
  const art = articles[idx] || {};
  return {
    company_name: m.company || '',
    article_id: art.id || null,
    sector_id: art.sector_id || 'unknown',
    context: (m.context || '').slice(0, 200),
    sentiment: ['positive','negative','neutral'].includes(m.sentiment) ? m.sentiment : 'neutral'
  };
}).filter(m => m.company_name);

console.log(`[NER] Batch ${batchData.batchIndex}: extracted ${results.length} mentions`);
return { json: { mentions: results } };

const items = $input.all();
const allMentions = [];
for (const item of items) {
  const mentions = item.json.mentions || [];
  allMentions.push(...mentions);
}
if (allMentions.length === 0) {
  console.log('[NER] No mentions to process');
  return [];
}
// 유니크 기업명 목록 추출 (ticker lookup용)
const uniqueNames = [...new Set(allMentions.map(m => m.company_name))];
console.log(`[NER] Total ${allMentions.length} mentions, ${uniqueNames.length} unique companies`);
return [{ json: { mentions: allMentions, uniqueNames } }];

// Aggregate Mentions의 데이터 + Fetch Ticker Map의 응답 합치기
const tickerData = $json; // HTTP Response: array of {company_name, ticker, full_name}
const mentionsData = $('Aggregate Mentions').first().json;
const mentions = mentionsData.mentions || [];

// Ticker map 구성
const tickerMap = {};
if (Array.isArray(tickerData)) {
  for (const row of tickerData) {
    tickerMap[row.company_name] = row;
  }
} else {
  // HTTP Request가 단일 아이템으로 온 경우
  const allItems = $input.all().map(i => i.json);
  for (const row of allItems) {
    if (row.company_name && row.ticker) tickerMap[row.company_name] = row;
  }
}

const now = new Date();
const mentionDate = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Seoul', year: 'numeric', month: '2-digit', day: '2-digit'
}).format(now);

// 티커 매핑 적용
const payload = mentions.map(m => {
  const mapped = tickerMap[m.company_name] || {};
  return {
    company_name: mapped.full_name || m.company_name,
    ticker: mapped.ticker || null,
    article_id: m.article_id,
    sector_id: m.sector_id,
    mention_date: mentionDate,
    context: m.context,
    sentiment: m.sentiment
  };
});

const matched = payload.filter(p => p.ticker).length;
console.log(`[NER] Ticker matched: ${matched}/${payload.length}`);

if (payload.length === 0) return [];
return [{ json: { mentions: payload } }];

